class DataStore<T extends { id: string | number }> {
  private data: T[];

  constructor(items: T[]) {
    this.data = items;
  }

  getPartial(): Partial<T>[] {
    return this.data.map(item => ({ ...item }));
  }

  getAsRecord(): Record<T['id'], T> {
    const record: Record<T['id'], T> = {} as Record<T['id'], T>;
    this.data.forEach(item => {
      record[item.id] = item;
    });
    return record;
  }

  getPicked<K extends keyof T>(...keys: K[]): Pick<T, K>[] {
    return this.data.map(item => {
      const picked = {} as Pick<T, K>;
      keys.forEach(key => {
        picked[key] = item[key];
      });
      return picked;
    });
  }
}

