// Define the utility type that maps input types to output types
type ProcessorResult<T> = T extends string ? string :
  T extends number ? number :
  T extends boolean ? string :
  T extends Array<infer U> ? U[] :
  never;

// Implement the DataProcessor class with function overloads
class DataProcessor {
  // Function overloads
  process(data: string): string;
  process(data: number): number;
  process(data: boolean): string;
  process<T>(data: T[]): T[];

  // Implementation
  process(data: unknown): unknown {
    // Type guard for string
    if (typeof data === 'string') {
      return data.toUpperCase();
    }
    // Type guard for number
    if (typeof data === 'number') {
      return data * data;
    }
    // Type guard for boolean
    if (typeof data === 'boolean') {
      return data ? 'YES' : 'NO';
    }
    // Type guard for array
    if (Array.isArray(data)) {
      return [...data].reverse();
    }
    // Default case for invalid inputs
    return null;
  }
}

// Usage example
const processor = new DataProcessor();
console.log(processor.process('hello'));        // 'HELLO'
console.log(processor.process(5));              // 25
console.log(processor.process(true));           // 'YES'
console.log(processor.process(false));          // 'NO'
console.log(processor.process([1, 2, 3]));      // [3, 2, 1]

