type EventListener<T> = T extends void ? () => void : (payload: T) => void;

class EventEmitter<EventMap extends Record<string, any>> {
  private listeners: Map<string, Set<Function>> = new Map();

  on<K extends keyof EventMap>(
    event: K,
    listener: EventListener<EventMap[K]>
  ): this {
    const key = String(event);
    if (!this.listeners.has(key)) {
      this.listeners.set(key, new Set());
    }
    this.listeners.get(key)!.add(listener);
    return this;
  }

  emit<K extends keyof EventMap>(
    event: K,
    ...args: EventMap[K] extends void ? [] : [EventMap[K]]
  ): void {
    const key = String(event);
    const eventListeners = this.listeners.get(key);
    if (eventListeners) {
      for (const listener of eventListeners) {
        if (args.length === 0) {
          (listener as () => void)();
        } else {
          (listener as (payload: any) => void)(args[0]);
        }
      }
    }
  }

  off<K extends keyof EventMap>(
    event: K,
    listener: EventListener<EventMap[K]>
  ): this {
    const key = String(event);
    const eventListeners = this.listeners.get(key);
    if (eventListeners) {
      eventListeners.delete(listener);
    }
    return this;
  }

  once<K extends keyof EventMap>(
    event: K,
    listener: EventListener<EventMap[K]>
  ): this {
    const onceWrapper = (...args: any[]) => {
      listener(...args);
      this.off(event, onceWrapper as EventListener<EventMap[K]>);
    };
    return this.on(event, onceWrapper as EventListener<EventMap[K]>);
  }
}

