type RequiredKeys<T> = {
  [K in keyof T]-?: {} extends Pick<T, K> ? never : K;
}[keyof T];

type OptionalKeys<T> = {
  [K in keyof T]-?: {} extends Pick<T, K> ? K : never;
}[keyof T];

type BuiltinExclude<T, U> = T extends U ? never : T;

class Builder<T, Built extends keyof T = never> {
  private data: Partial<T> = {};

  private set<K extends keyof T>(key: K, value: T[K]): Builder<T, Built | K> {
    (this.data as any)[key] = value;
    return this as any;
  }

  build(): Built extends RequiredKeys<T> ? T : never {
    const requiredKeys = Object.keys(this.data) as (keyof T)[];
    const allRequired = (Object.keys({} as Record<RequiredKeys<T>, any>) as (keyof T)[]);
    const hasAllRequired = allRequired.every((key) => requiredKeys.includes(key));

    if (!hasAllRequired) {
      throw new Error('Missing required fields');
    }
    return this.data as any;
  }
}

// Add a helper to generate setters dynamically
function createBuilderWithSetters<T>() {
  return new Proxy(new Builder<T>(), {
    get(target: any, prop: string) {
      if (prop.startsWith('set')) {
        const fieldName = prop.slice(3);
        const key = fieldName.charAt(0).toLowerCase() + fieldName.slice(1);
        return (value: any) => {
          return target.set(key, value);
        };
      }
      return target[prop];
    },
  }) as any;
}

// Alternative manual approach with explicit setters
class UserBuilder extends Builder<any> {
  setId(id: string): UserBuilder {
    return this['set']('id', id) as UserBuilder;
  }

  setName(name: string): UserBuilder {
    return this['set']('name', name) as UserBuilder;
