class EventEmitter<T extends Record<string, any>> {
  private listeners: Map<keyof T, Set<(payload: any) => void>> = new Map();

  on<K extends keyof T>(eventName: K, callback: (payload: T[K]) => void): void {
    if (!this.listeners.has(eventName)) {
      this.listeners.set(eventName, new Set());
    }
    this.listeners.get(eventName)!.add(callback as (payload: any) => void);
  }

  emit<K extends keyof T>(eventName: K, payload: T[K]): void {
    const callbacks = this.listeners.get(eventName);
    if (callbacks) {
      callbacks.forEach(callback => callback(payload));
    }
  }

  once<K extends keyof T>(eventName: K, callback: (payload: T[K]) => void): void {
    const onceWrapper = (payload: T[K]) => {
      callback(payload);
      this.off(eventName, onceWrapper);
    };
    this.on(eventName, onceWrapper);
  }

  off<K extends keyof T>(eventName: K, callback: (payload: T[K]) => void): void {
    const callbacks = this.listeners.get(eventName);
    if (callbacks) {
      callbacks.delete(callback as (payload: any) => void);
    }
  }
}

