// ============================================
// 1. Custom Awaited Type
// ============================================
type CustomAwaited<T> = T extends PromiseLike<infer U> ? CustomAwaited<U> : T;

// Test cases for Awaited
type Test1 = CustomAwaited<Promise<string>>; // string
type Test2 = CustomAwaited<Promise<Promise<number>>>; // number
type Test3 = CustomAwaited<string>; // string
type Test4 = CustomAwaited<PromiseLike<boolean>>; // boolean

// ============================================
// 2. Recursive JSON Type
// ============================================
type JSONValue = string | number | boolean | null | JSONValue[] | { [key: string]: JSONValue };

const validJSON: JSONValue = {
  name: 'test',
  age: 25,
  active: true,
  tags: ['a', 'b'],
  nested: { value: 42 }
};

// These cause type errors:
// const invalidJSON: JSONValue = { fn: () => {} };
// const invalidJSON2: JSONValue = { undef: undefined };

// ============================================
// 3. Phantom Types for Validated Data
// ============================================
type Validated<T, Brand extends string> = T & { readonly __validated__: Brand };

function validate<T>(data: unknown): Validated<T, 'validated'> {
  // Simple validation - in real code, would be more sophisticated
  if (data === null || data === undefined) {
    throw new Error('Invalid data');
  }
  return data as Validated<T, 'validated'>;
}

type ValidatedEmail = Validated<string, 'email'>;
type ValidatedPhone = Validated<string, 'phone'>;

const email = validate<string>('user@example.com') as ValidatedEmail;
// This causes a type error:
// const wrongAssign: ValidatedPhone = email;

// ============================================
// 4. Type-Safe Router with Param Extraction
// ============================================

// Extract parameter names from path string
type ExtractParamNames<Path extends string> = Path extends `${infer Prefix}:${infer Param}/${infer Rest}`
  ? Param extends `${infer ParamName}?`
    ? ParamName | ExtractParamNames<Rest>
    : Param | ExtractParamNames<Rest>
  : Path extends `${infer Prefix}:${infer Param}`
  ? Param extends `${infer ParamName}?`
    ? ParamName
    : Param
  : never;

// Extract parameters as an object type
type ExtractParams<Path extends string> = Path extends `${infer _}:${infer Rest}`
  ? ExtractParamNames<Path> extends infer ParamNames
    ? ParamNames extends string
      ? { [K in ParamNames]: string }
      : {}
    : {}
  : {};

interface Route<Path extends string> {
  path: Path;
  handler: (params: ExtractParams<Path>) => void;
}

class Router {
  private routes: Route<any>[] = [];

  get<Path extends string>(
    path: Path,
    handler: (params: ExtractParams<Path>) => void
  ): void {
    this.routes.push({ path, handler });
  }

  post<Path extends string>(
    path: Path,
    handler: (params: ExtractParams<Path>) => void
  ): void {
    this.routes.push({ path, handler });
  }

  handleRequest(path: string, method: string): void {
    const route = this.routes.find(r => r.path === path);
    if (route) {
      const params = this.extractParams(route.path, path);
      route.handler(params);
    }
  }

  private extractParams(pattern: string, actual: string): Record<string, string> {
    const patternParts = pattern.split('/');
    const actualParts = actual.split('/');
    const params: Record<string, string> = {};

    for (let i = 0; i < patternParts.length; i++) {
      if (patternParts[i].startsWith(':')) {
        const paramName = patternParts[i].slice(1).replace('?', '');
        params[paramName] = actualParts[i];
      }
    }

    return params;
  }
}

// Test usage
const router = new Router();
router.get('/users/:id', (params) => {
  // params has type { id: string }
  console.log(params.id);
});

router.get('/users/:userId/posts/:postId', (params) => {
  // params has type { userId: string; postId: string }
  console.log(params.userId, params.postId);
});

